mapper.select:
SELECT cc.id AS classId, c.course_no AS courseNo, c.name AS courseName, c.base_credit AS credit, c.type AS type, t.name AS teacherName, cc.time_location_info AS timeLocationInfo, cc.capacity AS capacity, cc.stock AS stock FROM course_class cc LEFT JOIN course c ON cc.course_id = c.id LEFT JOIN teacher t ON cc.teacher_id = t.id
AND cc.id = #{dto.id}
AND c.course_no = #{dto.courseNo}
AND c.name LIKE CONCAT('%', #{dto.name}, '%')
AND c.type = #{dto.type}
AND c.sub_type = #{dto.subType}
ORDER BY cc.id DESC
